import{_ as o,o as t,c as d,ah as i}from"./chunks/framework.Bi9enVNS.js";const p=JSON.parse('{"title":"错误与限制","description":"","frontmatter":{},"headers":[],"relativePath":"reference/errors-and-limits.md","filePath":"reference/errors-and-limits.md","lastUpdated":1774205896000}'),l={name:"reference/errors-and-limits.md"};function r(a,e,c,n,s,h){return t(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="错误与限制" tabindex="-1">错误与限制 <a class="header-anchor" href="#错误与限制" aria-label="Permalink to &quot;错误与限制&quot;">​</a></h1><p>这一页把协议错误、HTTP 状态码和实现限制放在一起，方便对照。</p><h2 id="批次级错误" tabindex="-1">批次级错误 <a class="header-anchor" href="#批次级错误" aria-label="Permalink to &quot;批次级错误&quot;">​</a></h2><p>下列情况会直接拒绝整批：</p><ul><li><code>request_id</code> 缺失</li><li><code>project</code> 缺失</li><li><code>environment</code> 缺失</li><li><code>producer</code> 缺失</li><li><code>producer.protocol_version != &quot;v1&quot;</code></li><li><code>records</code> 为空</li><li><code>records</code> 超过上限</li><li>body 解码失败</li><li><code>Content-Type</code> 不支持</li><li><code>Content-Encoding</code> 不支持</li></ul><h2 id="记录级错误" tabindex="-1">记录级错误 <a class="header-anchor" href="#记录级错误" aria-label="Permalink to &quot;记录级错误&quot;">​</a></h2><p>下列情况会让单条记录进入 <code>errors[]</code>：</p><ul><li>缺少 <code>event_time</code></li><li><code>severity_number</code> 超出 <code>0..24</code></li><li>有效来源解析失败</li><li><code>trace_id</code> 格式不合法</li><li><code>span_id</code> 格式不合法</li><li><code>trace_flags</code> 格式不合法</li></ul><h2 id="http-状态码对照" tabindex="-1">HTTP 状态码对照 <a class="header-anchor" href="#http-状态码对照" aria-label="Permalink to &quot;HTTP 状态码对照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态码</th><th>说明</th></tr></thead><tbody><tr><td><code>200</code></td><td>上传成功，或者部分成功</td></tr><tr><td><code>400</code></td><td>请求无效、解码失败、参数格式错误</td></tr><tr><td><code>401</code></td><td>缺少 Bearer token，或 token 无权写入当前 project</td></tr><tr><td><code>413</code></td><td>请求体超过最大限制</td></tr><tr><td><code>500</code></td><td>归一化或存储阶段的内部错误</td></tr></tbody></table><h2 id="当前限制" tabindex="-1">当前限制 <a class="header-anchor" href="#当前限制" aria-label="Permalink to &quot;当前限制&quot;">​</a></h2><ul><li>默认单请求最多 <code>1000</code> 条日志</li><li>默认解压后请求体最大 <code>1 MiB</code></li><li>只提供内存存储</li><li>幂等缓存只保存在当前进程</li><li>幂等 TTL 固定 24 小时</li><li>查询接口无分页</li><li>查询结果排序逻辑是代码内固定的默认行为</li></ul><h2 id="当前不会做的事" tabindex="-1">当前不会做的事 <a class="header-anchor" href="#当前不会做的事" aria-label="Permalink to &quot;当前不会做的事&quot;">​</a></h2><ul><li>不会自动根据 span parent-child 关系构图</li><li>不会把 <code>observed_time</code> 暴露到查询响应</li><li>不会把 attributes/resource 纳入 <code>keyword</code> 搜索</li></ul><h2 id="事实来源" tabindex="-1">事实来源 <a class="header-anchor" href="#事实来源" aria-label="Permalink to &quot;事实来源&quot;">​</a></h2><ul><li><code>docs/protocol.md</code></li><li><code>internal/api/http.go</code></li><li><code>internal/ingest/decode.go</code></li><li><code>internal/ingest/service.go</code></li><li><code>internal/ingest/validate.go</code></li><li><code>internal/store/memory/memory.go</code></li></ul>',16)])])}const m=o(l,[["render",r]]);export{p as __pageData,m as default};
